{"content":"// === Neon Pac VR — Entry Point ===

import {
  World,
  PanelUI,
  Follower,
  ScreenSpace,
  FogExp2,
  Color,
} from '@iwsdk/core';
import { buildMazeGroup, DotGrid, gridToWorld, PACMAN_START } from './maze';
import { GameManager } from './game';
import { GameSystem } from './game-system';
import { UISystem } from './ui-system';
import { MAZE_OFFSET_Y } from './types';

async function main(): Promise<void> {
  const container = document.getElementById('app') as HTMLDivElement;

  // Create world — VR with browser fallback
  const world = await World.create(container, {
    xr: { offer: 'once' },
    render: {
      near: 0.01,
      far: 50,
      camera: {
        position: [0, 2.4, 1.2],
        lookAt: [0, MAZE_OFFSET_Y, -0.2],
      },
    },
    input: { canvasPointerEvents: true },
    features: {
      locomotion: { browserControls: true },
      physics: false,
    },
  });

  // Fog for atmosphere
  world.scene.fog = new FogExp2(0x000811, 0.15);
  world.scene.background = new Color(0x000811);

  // Build maze
  const dotGrid = new DotGrid();
  const { mazeGroup, dotMeshes, pacmanMesh, ghostMeshes } = buildMazeGroup();
  world.scene.add(mazeGroup);

  // Create game manager
  const game = new GameManager(pacmanMesh, ghostMeshes, dotGrid, dotMeshes);

  // ---- PanelUI setup ----
  // HUD — follows player head (ScreenSpace for browser, Follower for XR)
  const hudEntity = world.createTransformEntity(undefined, {
    parent: world.playerHeadEntity,
    persistent: true,
  });
  hudEntity.addComponent(PanelUI, { config: './ui/hud.json' });
  hudEntity.addComponent(Follower, {});
  // Position HUD offset
  const hudOff = hudEntity.getVectorView(Follower, 'offsetPosition');
  if (hudOff) {
    hudOff[0] = 0;    // x
    hudOff[1] = -0.25; // y (below eye level)
    hudOff[2] = -0.8;  // z (in front)
  }
  hudEntity.object3D!.scale.setScalar(0.0008);

  // Menu panel — world-anchored above maze
  const menuPos = gridToWorld(10, 10);
  const menuEntity = world.createTransformEntity();
  menuEntity.object3D!.position.set(menuPos.x, MAZE_OFFSET_Y + 0.6, menuPos.z);
  menuEntity.object3D!.rotation.x = -0.3;
  menuEntity.object3D!.scale.setScalar(0.0012);
  menuEntity.addComponent(PanelUI, { config: './ui/menu.json' });

  // Game over panel — same position as menu
  const gameoverEntity = world.createTransformEntity();
  gameoverEntity.object3D!.position.set(menuPos.x, MAZE_OFFSET_Y + 0.6, menuPos.z);
  gameoverEntity.object3D!.rotation.x = -0.3;
  gameoverEntity.object3D!.scale.setScalar(0.0012);
  gameoverEntity.object3D!.visible = false;
  gameoverEntity.addComponent(PanelUI, { config: './ui/gameover.json' });

  // Pause panel
  const pauseEntity = world.createTransformEntity();
  pauseEntity.object3D!.position.set(menuPos.x, MAZE_OFFSET_Y + 0.6, menuPos.z);
  pauseEntity.object3D!.rotation.x = -0.3;
  pauseEntity.object3D!.scale.setScalar(0.0012);
  pauseEntity.object3D!.visible = false;
  pauseEntity.addComponent(PanelUI, { config: './ui/pause.json' });

  // ---- Register systems ----
  world.registerSystem(GameSystem);
  world.registerSystem(UISystem);

  const gameSystem = world.getSystem(GameSystem)!;
  gameSystem.setRefs({ game });

  const uiSystem = world.getSystem(UISystem)!;
  uiSystem.setRefs({
    game,
    hudEntity,
    menuEntity,
    gameoverEntity,
    pauseEntity,
  });
}

main().catch(console.error);
